head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -7); // 현재 기준 일주일 전 날짜
scwin.ed_lineCd = "";

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    const codeOptions = [
        { grpCd: "FS500", compID: "acb_sellDcsnClsCd"}, // 셀렉트
        { grpCd: "FS800", compID: "acb_bilgOdrKndCd"}, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);



};


//-------------------------------------------------------------------------
// UDC 기본값 세팅
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    udc_qryConDt.setInitDate(scwin.strPreDate, scwin.strCurDate);
    ed_bilgLodeptCd.focus();
}


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {

    //validation check     
    if(! await $c.gus.cfValidate([ed_bilgLodeptCd, ica_qryConDtFm, ica_qryConDtTo])){
        return;
    }

    //조회시작일자가 더 클경우 체크
    if (!await $c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
        cfAlertMsg(MSG_CM_ERR_039);
        return;
    }



    dma_generalbillingorder_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());

    if(acb_qryConKnd.getValue() == "오더"){
        qryConKnd = "오더";
        // gr_generalbillingorder.setcolumngead('rsltsStdDt', 'Name')     = "오더일자";     		
    } 

    dma_generalbillingorder_con.set("qryConKnd", acb_qryConKnd.getValue());
    dma_generalbillingorder_con.set("qryConDtFm", ica_qryConDtFm.getValue());
    dma_generalbillingorder_con.set("qryConDtTo", ica_qryConDtTo.getValue());
    dma_generalbillingorder_con.set("bilgClntNo", ed_bilgClntNo.getValue()); 	
    dma_generalbillingorder_con.set("bilgOdrKndCd", acb_bilgOdrKndCd.getValue());
    dma_generalbillingorder_con.set("sellDcsnClsCd", acb_sellDcsnClsCd.getValue());

    $c.sbm.execute(sbm_generalbillingorder_retrieve)

};


//-------------------------------------------------------------------------
// UDC 공통 팝업 (청구부서)
//-------------------------------------------------------------------------
scwin.udc_bilgLodept_onClick = async function (e) {

    udc_bilgLodept.cfCommonPopUp(scwin.udc_bilgLodept_callBackFunc
    , ed_bilgLodeptCd.getValue()
    ,ed_bilgLodeptNm.getValue()
    ,"T"					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
    ,null					// Title순서	
    ,null					// 보여주는 각 컬럼들의 폭	
    ,null					// 컬럼중에서 숨기는	컬럼 지정	
    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
    ,null					// 윈도우 위치 Y좌표	
    ,null					// 윈도우 위치 X좌표
    ,null					// 중복체크여부	("F")
    ,null				// 전체검색허용여부	("F")
    ,"청구부서코드,부서코드,부서명"			// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
    );
};

