//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onClick = function (e) {
    $c.gus.cfInitObjects(tbl_search,[ed_bilgLodeptCd,ed_bilgLodeptNm,ica_qryConDtFm,ica_qryConDtTo]);

};


//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderDetail = function(arg) {

  	if(arg != "NEW" && ds_generalbillingorder.getRowCount() == 0){
  		$c.win.alert($c.data.getMessage(MSG_CM_WRN_008,"오더내역"));
  		return;
  	}

  	let row = ds_generalbillingorder.getRowPosition();
  	let strOrderDetailUrl = "/ui/ds/fs/bilg/fs_202_03_02b.xml";

  	// 선택된 오더 정보 : 오더번호 , flag
    let odrNo = ds_generalbillingorder.getCellData(row, "odrNo");

    let paramObj = {
        v_odrNo : odrNo,
        v_flag  : arg
    }

    let option = {

    }    

    $c.win.openMenu("일반청구오더관리", strOrderDetailUrl, "fs_202_03_02b", paramObj, option)


}


//-------------------------------------------------------------------------
// 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_generalbillingorder_ondataload = function () {

    spa_totalRows.setValue(ds_generalbillingorder.getTotalRow());

    if(ds_generalbillingorder.getTotalRow() == 0) {
        $c.win.alert(MSG_CM_WRN_002);
        ed_bilgLodeptCd.focus();
    }


    for(i = 0; i < ds_generalbillingorder.getTotalRow(); i++) {
        let vsslCd = ds_generalbillingorder.getCellData(i, "vsslCd")
        let portcnt = ds_generalbillingorder.getCellData(i, "portcnt")

        ds_generalbillingorder.setCellData(i, "vsslCd", (vsslCd + "-" +portcnt));
    }

    gr_generalbillingorder.setFocusedCell(0, 0);

    // let options = {
    //     sortIndex : "odrNo odrDt bilgOdrKndNm sellClntNm pchsClntNm vsslCd",
    //     sortOrder : "1 1 1 1 1 1"
    // }

    // ds_generalbillingorder.multisort(options);


};

//-------------------------------------------------------------------------
// 그리드 더블 클릭
//-------------------------------------------------------------------------
scwin.gr_dblClick = function (rowIndex, columnIndex, columnId) {
    // 오더 세부사항 조회
    if(rowIndex >= 0) {
        scwin.f_orderDetail("DETAIL");
    }

};

//-------------------------------------------------------------------------
// 참조신규 버튼 클릭시
//-------------------------------------------------------------------------
scwin.btn_ctrtChg_onClick = function (e) {

    scwin.f_orderDetail("REFERENCE");

};

//-------------------------------------------------------------------------
// 신규 버튼 클릭시
//-------------------------------------------------------------------------
scwin.btn_ctrtEdit_onClick = function (e) {

    scwin.f_orderDetail("NEW");

};

//-------------------------------------------------------------------------
// 상세 버튼 클릭시
//-------------------------------------------------------------------------
scwin.btn_ctrtPrint_onClick = function (e) {

    scwin.f_orderDetail("DETAIL");

};
